args.sparql:
SELECT ?country ?countryLabel (AVG(?turnout) AS ?avgTurnout)
WHERE {
  ?country wdt:P463 wd:Q1566.
  ?country wdt:P31 wd:Q3624.
  ?election wdt:P17 ?country;
            wdt:P31 wd:Q41727;
            wdt:P585 ?electionDate;
            wdt:P911 ?turnout.
  FILTER(?electionDate >= "2013-01-01"^^xsd:dateTime && ?electionDate <= "2023-12-31"^^xsd:dateTime)
  OPTIONAL { ?country rdfs:label ?countryLabel FILTER(LANG(?countryLabel) = "en") }
}
GROUP BY ?country ?countryLabel

